#!/usr/bin/env node
import { readFile, writeFile } from "node:fs/promises";
import { basename, dirname, join, normalize, relative, resolve } from "node:path";
import { fileURLToPath, pathToFileURL } from "node:url";

const root = resolve(dirname(fileURLToPath(import.meta.url)), "..");
const srcRoot = join(root, "src");
const entry = "src/browser.js";
const outFiles = {
  esm: join(root, "browser.js"),
  esmMin: join(root, "browser.min.js"),
  umd: join(root, "browser.umd.js"),
  umdMin: join(root, "browser.umd.min.js"),
  ts: join(root, "browser.ts"),
  browserDts: join(root, "browser.d.ts"),
  serverDts: join(root, "server.d.ts")
};
const check = process.argv.includes("--check");

const modules = new Map();

await loadModule(entry);
const ordered = topoSort(entry).filter((file) => file !== entry);
const publicExports = modules.get(entry).reexports;

const chunks = [];

for (const file of ordered) {
  const module = modules.get(file);
  const imports = module.imports.map((item) => {
    const dependency = moduleVariable(item.source);
    const specifiers = item.specifiers
      .map(({ imported, local }) => imported === local ? imported : `${imported}: ${local}`)
      .join(", ");
    return `  const { ${specifiers} } = ${dependency};`;
  });

  chunks.push(`const ${moduleVariable(file)} = (() => {`);
  chunks.push(...imports);
  chunks.push(indent(stripExports(removeImports(module.source)).trim()));
  chunks.push(`  return { ${module.exports.join(", ")} };`);
  chunks.push("})();");
  chunks.push("");
}

const publicBindings = [];
for (const item of publicExports) {
  const local = item.exported;
  publicBindings.push(local);
  chunks.push(`const { ${item.imported}: ${local} } = ${moduleVariable(item.source)};`);
}

const umdNamespaceReservedKeys = await readUmdNamespaceReservedKeys();
assertNoUmdNamespaceConflicts(publicBindings, umdNamespaceReservedKeys);

const bundleBody = `${chunks.join("\n")}`;
const esmOutput = [
  "// Generated by scripts/build-framework-bundle.js. Do not edit by hand.",
  "// Bundled ESM entry for CDN imports.",
  "",
  bundleBody,
  "",
  `export { ${publicBindings.join(", ")} };`,
  ""
].join("\n");
const esmMinOutput = compactJavaScript(esmOutput);
const umdOutput = [
  "// Generated by scripts/build-framework-bundle.js. Do not edit by hand.",
  "// Bundled UMD entry for script-tag and CommonJS-style consumers.",
  "(function (root, factory) {",
  "  const namespace = factory();",
  "  if (typeof define === \"function\" && define.amd) {",
  "    define([], function () { return namespace; });",
  "  } else if (typeof module === \"object\" && module.exports) {",
  "    module.exports = namespace;",
  "  } else {",
  "    root.AsyncFramework = namespace;",
  "    root.Async = namespace;",
  "  }",
  "})(typeof globalThis !== \"undefined\" ? globalThis : typeof self !== \"undefined\" ? self : this, function () {",
  "  \"use strict\";",
  indent(bundleBody.trim()),
  `  const api = { ${publicBindings.join(", ")} };`,
  "  assertNoUmdNamespaceConflicts(api, Async);",
  "  Object.assign(Async, api);",
  "  Async.Async = Async;",
  "  return Async;",
  "",
  "  function assertNoUmdNamespaceConflicts(api, target) {",
  "    const conflicts = Object.keys(api).filter((key) => key !== \"Async\" && Object.prototype.hasOwnProperty.call(target, key));",
  "    if (conflicts.length > 0) {",
  "      throw new Error(`UMD Async namespace export conflict: ${conflicts.join(\", \")}.`);",
  "    }",
  "  }",
  "});",
  ""
].join("\n");
const umdMinOutput = compactJavaScript(umdOutput);
